from dataclasses import dataclass, field
from typing import Callable

@dataclass
class Goal:
    description: str
    test: Callable[[dict], bool]  # returns True when goal is achieved
    priority: int = 0

class ProactiveAgent:
    def __init__(self):
        self.goals = []       # active goal stack (highest priority first)
        self.world_state = {} # agent's model of the environment

    def add_goal(self, goal):
        self.goals.append(goal)
        self.goals.sort(key=lambda g: -g.priority)

    def pursue_goals(self, max_steps=20):
        step = 0
        while self.goals and step < max_steps:
            current = self.goals[0]
            if current.test(self.world_state):
                print('Goal achieved: ' + current.description)
                self.goals.pop(0)
                continue
            action = self._select_action(current)
            if action is None:
                print('No action available for: ' + current.description)
                self.goals.pop(0)
                continue
            self._execute(action)
            step += 1

    def _select_action(self, goal):
        # Stub: real agents use planning or LLM reasoning here
        return 'step_toward_' + goal.description.replace(' ', '_')

    def _execute(self, action):
        print('Executing: ' + action)
        # Update world_state based on action effect
        self.world_state[action] = True

agent = ProactiveAgent()
agent.add_goal(Goal('tests passing', test=lambda s: s.get('tests_ok', False), priority=2))
agent.add_goal(Goal('docs updated', test=lambda s: s.get('docs_ok', False), priority=1))
agent.pursue_goals(max_steps=4)

import threading
import time

class ScheduledProactiveAgent:
    def __init__(self):
        self._tasks = []  # list of (interval_s, last_run, fn, name)
        self._running = False

    def schedule(self, interval_s, fn, name='task'):
        self._tasks.append({'interval': interval_s, 'last': 0, 'fn': fn, 'name': name})

    def start(self):
        self._running = True
        thread = threading.Thread(target=self._loop, daemon=True)
        thread.start()
        return thread

    def stop(self):
        self._running = False

    def _loop(self):
        while self._running:
            now = time.monotonic()
            for task in self._tasks:
                if now - task['last'] >= task['interval']:
                    print('[Proactive] Running: ' + task['name'])
                    try:
                        task['fn']()
                    except Exception as exc:
                        print('[Proactive] Error in ' + task['name'] + ': ' + str(exc))
                    task['last'] = now
            time.sleep(0.1)

def check_disk_usage():
    import shutil
    total, used, free = shutil.disk_usage('/')
    pct = used * 100 // total
    if pct > 85:
        print('  WARN: disk at ' + str(pct) + '%')
    else:
        print('  OK: disk at ' + str(pct) + '%')

def check_pending_updates():
    print('  Scanning for available package updates...')

agent = ScheduledProactiveAgent()
agent.schedule(interval_s=300, fn=check_disk_usage, name='disk-check')
agent.schedule(interval_s=3600, fn=check_pending_updates, name='update-scan')
