# Simplified proactive LLM agent: decomposes and pursues a goal
from dataclasses import dataclass

@dataclass
class SubTask:
    description: str
    completed: bool = False

class ProactiveLLMAgent:
    def __init__(self, tools):
        self.tools = tools
        self.sub_tasks = []

    def set_goal(self, goal):
        # Step 1: proactively decompose the goal into sub-tasks
        self.sub_tasks = self._decompose(goal)
        print('Goal: ' + goal)
        print('Plan (' + str(len(self.sub_tasks)) + ' sub-tasks):')
        for i, st in enumerate(self.sub_tasks):
            print('  ' + str(i+1) + '. ' + st.description)

    def run(self):
        for sub_task in self.sub_tasks:
            if sub_task.completed:
                continue
            # Step 2: proactively gather info needed for this sub-task
            context = self._gather_context(sub_task)
            # Step 3: execute the sub-task
            result = self._execute_sub_task(sub_task, context)
            sub_task.completed = True
            print('Completed: ' + sub_task.description + ' -> ' + result)

    def _decompose(self, goal):
        # In production: LLM call with goal -> sub-task list
        return [
            SubTask('Read current codebase structure'),
            SubTask('Identify files to modify'),
            SubTask('Make changes'),
            SubTask('Run tests'),
            SubTask('Report results'),
        ]

    def _gather_context(self, sub_task):
        # Proactively read relevant files, check env, etc.
        return {'env': 'production', 'last_run': 'success'}

    def _execute_sub_task(self, sub_task, context):
        return 'done'

agent = ProactiveLLMAgent(tools={})
agent.set_goal('Add input validation to the login endpoint')
agent.run()

class BoundedProactiveAgent:
    def __init__(self, allowed_scope, dry_run=False):
        self.allowed_scope = set(allowed_scope)
        self.dry_run = dry_run
        self.proactive_actions = []  # audit log of self-initiated actions

    def act_on_initiative(self, action_type, description, fn, irreversible=False):
        if action_type not in self.allowed_scope:
            print('[Proactive] Skipped out-of-scope action: ' + description)
            return None

        if irreversible and self.dry_run:
            print('[Proactive] DRY-RUN -- would have done: ' + description)
            return None

        print('[Proactive] Taking initiative: ' + description)
        result = fn() if not self.dry_run else 'dry-run'
        self.proactive_actions.append({'action': description, 'result': result})
        return result

    def report(self):
        if not self.proactive_actions:
            print('No proactive actions taken.')
            return
        print('Proactive actions taken this session:')
        for pa in self.proactive_actions:
            print('  - ' + pa['action'] + ' -> ' + str(pa['result']))

agent = BoundedProactiveAgent(
    allowed_scope=['lint_check', 'format_code', 'run_tests'],
    dry_run=True,
)
agent.act_on_initiative(
    'lint_check', 'Spotted unused import -- removing it',
    fn=lambda: 'removed import',
)
agent.act_on_initiative(
    'delete_file', 'Noticed old backup -- deleting',
    fn=lambda: 'deleted',
    irreversible=True,
)
agent.report()

import heapq
from dataclasses import dataclass, field

@dataclass(order=True)
class PrioritisedGoal:
    priority: float          # lower number = higher priority
    description: str = field(compare=False)
    deadline: float = field(compare=False, default=float('inf'))
    effort_estimate: float = field(compare=False, default=1.0)

class MultiGoalAgent:
    def __init__(self):
        self._heap = []  # min-heap by priority

    def add_goal(self, description, priority, deadline=float('inf'), effort=1.0):
        goal = PrioritisedGoal(priority=priority, description=description,
                               deadline=deadline, effort_estimate=effort)
        heapq.heappush(self._heap, goal)

    def next_goal(self):
        if self._heap:
            return heapq.heappop(self._heap)
        return None

    def run_one_step(self):
        goal = self.next_goal()
        if goal is None:
            print('No active goals -- agent idle')
            return
        print('Pursuing (priority ' + str(goal.priority) + '): ' + goal.description)
        # ... execute steps toward goal ...

agent = MultiGoalAgent()
agent.add_goal('fix critical bug', priority=1)
agent.add_goal('update documentation', priority=5)
agent.add_goal('refactor old module', priority=3)

for _ in range(3):
    agent.run_one_step()
# Output: critical bug first, then refactor, then docs

from pathlib import Path

class ProactiveContextGatherer:
    def __init__(self, tools):
        self.tools = tools
        self.context = {}

    def gather_for_task(self, task_description):
        # Proactively read files/configs the task will likely need
        reads = self._predict_needed_context(task_description)
        print('Pre-gathering context for: ' + task_description)
        for resource in reads:
            value = self._read(resource)
            self.context[resource] = value
            print('  Loaded: ' + resource)
        return self.context

    def _predict_needed_context(self, task):
        # In production: LLM predicts which files/configs are needed
        # Here: simple keyword-based heuristic
        needed = []
        if 'test' in task.lower():
            needed.extend(['pytest.ini', 'pyproject.toml'])
        if 'deploy' in task.lower():
            needed.extend(['.env.production', 'Dockerfile'])
        if 'database' in task.lower():
            needed.extend(['alembic.ini', 'models.py'])
        return needed

    def _read(self, resource):
        p = Path(resource)
        if p.exists():
            return p.read_text()[:200]
        return '[not found]'

gatherer = ProactiveContextGatherer(tools={})
context = gatherer.gather_for_task('run the test suite and fix failures')
print('Context keys ready:', list(context.keys()))

from dataclasses import dataclass, field

@dataclass
class Plan:
    steps: list
    step_index: int = 0
    retries: dict = field(default_factory=dict)
    max_retries: int = 2

    def current_step(self):
        if self.step_index < len(self.steps):
            return self.steps[self.step_index]
        return None

    def advance(self):
        self.step_index += 1

class ReplanningAgent:
    def __init__(self, goal):
        self.goal = goal

    def run(self):
        plan = self._make_plan(self.goal)
        while True:
            step = plan.current_step()
            if step is None:
                print('Goal achieved: ' + self.goal)
                return True

            print('Executing step: ' + step)
            success, error = self._try_step(step)

            if success:
                plan.advance()
            else:
                retries = plan.retries.get(step, 0)
                if retries < plan.max_retries:
                    plan.retries[step] = retries + 1
                    print('Step failed (' + error + ') -- retry ' + str(retries+1))
                else:
                    print('Step failed after max retries -- replanning')
                    new_plan = self._replan(self.goal, step, error, plan)
                    if new_plan is None:
                        print('Cannot achieve goal: ' + self.goal)
                        return False
                    plan = new_plan

    def _make_plan(self, goal):
        return Plan(steps=['gather_context', 'make_changes', 'run_tests', 'commit'])

    def _try_step(self, step):
        # Stub: simulate occasional failure
        if step == 'run_tests':
            return False, 'test_failure: assertion error in test_login'
        return True, ''

    def _replan(self, goal, failed_step, error, old_plan):
        # Agent proactively devises an alternative sequence
        print('Devising alternative plan after: ' + failed_step)
        # Skip failed step, add fix step
        remaining = old_plan.steps[old_plan.step_index:]
        new_steps = ['fix_test_failures'] + remaining
        return Plan(steps=new_steps)

agent = ReplanningAgent(goal='ship the auth feature')
agent.run()
